module top_module(input wire [3:0] in, input wire [1:0] s, output wire out);reg [3:0] obf_temp;
    always @(in or s)
        case (s)
            2'b00: obf_temp = in[0];
            2'b01: obf_temp = in[1];
            2'b10: obf_temp = in[2];
            2'b11: obf_temp = in[3];
            default: obf_temp = 4'b0;
        endcase
    assign out = obf_temp;
endmodule
